<?php header('Content-type: application/javascript'); ?>
<?php
$current_version = isset($_GET['v']) ? urldecode($_GET['v']) : 'Latest'; ?>
document.write('<select onchange="window.location.href=\'/docs/api/\' + this.value + \'/\';" name="api-version-selector" class="api-version-selector">');
<?php 
  $dirs = str_replace('../api/', '', array_filter(glob('../api/*'), 'is_dir'));
  // Remove latest key so we can add it later
  $latest_key = array_search('latest', $dirs);
  if($latest_key) {
    unset($dirs[$latest_key]);
  }
  // Sort the dirs
  usort($dirs, 'version_compare');
  // Sort the dirs in reverse-chron order
  $dirs = array_reverse($dirs);
  // Find the most recent version 
  $latest_version = $dirs[0];
  if($current_version == $latest_version) {
    $current_version = 'latest';
  }
  // Remove the current version key so it's not duplicated
  unset($dirs[0]);
  // Add latest to beginning of the versions array
  array_unshift($dirs, 'Latest (' . $latest_version . ')');
  foreach($dirs as $dir) : 
  $version = $dir;
  if(strpos($dir, 'Latest') !== FALSE) {
    $version = 'latest';
  }
?>
document.write('<option value="<?php print strtolower($version) ?>"<?php if($current_version == $version){ ?> selected="selected" <?php } ?>><?php print $dir ?></option>');
<?php endforeach; ?>
document.write('</select>');